2462   /// Remove instructions from the parent function and clear the operands of \p
2463   /// DeadVals instructions, marking for deletion trivially dead operands.
2464   template <typename T>
2465   void removeInstructionsAndOperands(ArrayRef<T *> DeadVals) {
2466     SmallVector<WeakTrackingVH> DeadInsts;
2467     for (T *V : DeadVals) {
2468       auto *I = cast<Instruction>(V);
2469       DeletedInstructions.insert(I);
2470     }
2471     for (T *V : DeadVals) {
2472       if (!V)
2473         continue;
2474       auto *I = cast<Instruction>(V);
2475       salvageDebugInfo(*I);
2476       SmallVector<const TreeEntry *> Entries;
2477       if (const TreeEntry *Entry = getTreeEntry(I)) {
2478         Entries.push_back(Entry);
2479         auto It = MultiNodeScalars.find(I);
2480         if (It != MultiNodeScalars.end())
2481           Entries.append(It->second.begin(), It->second.end());
2482       }
2483       for (Use &U : I->operands()) {
2484         if (auto *OpI = dyn_cast_if_present<Instruction>(U.get());
2485             OpI && !DeletedInstructions.contains(OpI) && OpI->hasOneUser() &&
2486             wouldInstructionBeTriviallyDead(OpI, TLI) &&
2487             (Entries.empty() || none_of(Entries, [&](const TreeEntry *Entry) {
2488                return Entry->VectorizedValue == OpI;
2489              })))
2490           DeadInsts.push_back(OpI);
2491       }
2492       I->dropAllReferences();
2493     }
2494     for (T *V : DeadVals) {
2495       auto *I = cast<Instruction>(V);
2496       if (!I->getParent())
2497         continue;
2498       assert((I->use_empty() || all_of(I->uses(),
2499                                        [&](Use &U) {
2500                                          return isDeleted(
2501                                              cast<Instruction>(U.getUser()));
2502                                        })) &&
2503              "trying to erase instruction with users.");
2504       I->removeFromParent();
2505       SE->forgetValue(I);
2506     }
2507     // Process the dead instruction list until empty.
2508     while (!DeadInsts.empty()) {
2509       Value *V = DeadInsts.pop_back_val();
2510       Instruction *VI = cast_or_null<Instruction>(V);
2511       if (!VI || !VI->getParent())
2512         continue;
2513       assert(isInstructionTriviallyDead(VI, TLI) &&
2514              "Live instruction found in dead worklist!");
2515       assert(VI->use_empty() && "Instructions with uses are not dead.");
2516 
2517       // Don't lose the debug info while deleting the instructions.
2518       salvageDebugInfo(*VI);
2519 
2520       // Null out all of the instruction's operands to see if any operand
2521       // becomes dead as we go.
2522       for (Use &OpU : VI->operands()) {
2523         Value *OpV = OpU.get();
2524         if (!OpV)
2525           continue;
2526         OpU.set(nullptr);
2527 
2528         if (!OpV->use_empty())
2529           continue;
2530 
2531         // If the operand is an instruction that became dead as we nulled out
2532         // the operand, and if it is 'trivially' dead, delete it in a future
2533         // loop iteration.
2534         if (auto *OpI = dyn_cast<Instruction>(OpV))
2535           if (!DeletedInstructions.contains(OpI) &&
2536               isInstructionTriviallyDead(OpI, TLI))
2537             DeadInsts.push_back(OpI);
2538       }
2539 
2540       VI->removeFromParent();
2541       DeletedInstructions.insert(VI);
2542       SE->forgetValue(VI);
2543     }
2544   }
