18004 /// Try and get a reduction instruction from a phi node.
18005 ///
18006 /// Given a phi node \p P in a block \p ParentBB, consider possible reductions
18007 /// if they come from either \p ParentBB or a containing loop latch.
18008 ///
18009 /// \returns A candidate reduction value if possible, or \code nullptr \endcode
18010 /// if not possible.
18011 static Instruction *getReductionInstr(const DominatorTree *DT, PHINode *P,
18012                                       BasicBlock *ParentBB, LoopInfo *LI) {
18013   // There are situations where the reduction value is not dominated by the
18014   // reduction phi. Vectorizing such cases has been reported to cause
18015   // miscompiles. See PR25787.
18016   auto DominatedReduxValue = [&](Value *R) {
18017     return isa<Instruction>(R) &&
18018            DT->dominates(P->getParent(), cast<Instruction>(R)->getParent());
18019   };
18020 
18021   Instruction *Rdx = nullptr;
18022 
18023   // Return the incoming value if it comes from the same BB as the phi node.
18024   if (P->getIncomingBlock(0) == ParentBB) {
18025     Rdx = dyn_cast<Instruction>(P->getIncomingValue(0));
18026   } else if (P->getIncomingBlock(1) == ParentBB) {
18027     Rdx = dyn_cast<Instruction>(P->getIncomingValue(1));
18028   }
18029 
18030   if (Rdx && DominatedReduxValue(Rdx))
18031     return Rdx;
18032 
18033   // Otherwise, check whether we have a loop latch to look at.
18034   Loop *BBL = LI->getLoopFor(ParentBB);
18035   if (!BBL)
18036     return nullptr;
18037   BasicBlock *BBLatch = BBL->getLoopLatch();
18038   if (!BBLatch)
18039     return nullptr;
18040 
18041   // There is a loop latch, return the incoming value if it comes from
18042   // that. This reduction pattern occasionally turns up.
18043   if (P->getIncomingBlock(0) == BBLatch) {
18044     Rdx = dyn_cast<Instruction>(P->getIncomingValue(0));
18045   } else if (P->getIncomingBlock(1) == BBLatch) {
18046     Rdx = dyn_cast<Instruction>(P->getIncomingValue(1));
18047   }
18048 
18049   if (Rdx && DominatedReduxValue(Rdx))
18050     return Rdx;
18051 
18052   return nullptr;
18053 }
