14493 void BoUpSLP::BlockScheduling::cancelScheduling(ArrayRef<Value *> VL,
14494                                                 Value *OpValue) {
14495   if (isa<PHINode>(OpValue) || isVectorLikeInstWithConstOps(OpValue) ||
14496       doesNotNeedToSchedule(VL))
14497     return;
14498 
14499   if (doesNotNeedToBeScheduled(OpValue))
14500     OpValue = *find_if_not(VL, doesNotNeedToBeScheduled);
