14509   // Remove the bundle from the ready list.
14510   if (Bundle->isReady())
14511     ReadyInsts.remove(Bundle);
14512 
14513   // Un-bundle: make single instructions out of the bundle.
14514   ScheduleData *BundleMember = Bundle;
14515   while (BundleMember) {
14516     assert(BundleMember->FirstInBundle == Bundle && "corrupt bundle links");
14517     BundleMember->FirstInBundle = BundleMember;
14518     ScheduleData *Next = BundleMember->NextInBundle;
14519     BundleMember->NextInBundle = nullptr;
14520     BundleMember->TE = nullptr;
