14504          "Can't cancel bundle which is already scheduled");
14505   assert(Bundle->isSchedulingEntity() &&
14506          (Bundle->isPartOfBundle() || needToScheduleSingleInstruction(VL)) &&
14507          "tried to unbundle something which is not a bundle");
