14885   // sorted by the original instruction location. This lets the final schedule
14886   // be as  close as possible to the original instruction order.
14887   // WARNING: If changing this order causes a correctness issue, that means
14888   // there is some missing dependence edge in the schedule data graph.
14889   struct ScheduleDataCompare {
14890     bool operator()(ScheduleData *SD1, ScheduleData *SD2) const {
14891       return SD2->SchedulingPriority < SD1->SchedulingPriority;
