14900        I = I->getNextNode()) {
14901     BS->doForAllOpcodes(I, [this, &Idx, BS](ScheduleData *SD) {
14902       TreeEntry *SDTE = getTreeEntry(SD->Inst);
14903       (void)SDTE;
14904       assert((isVectorLikeInstWithConstOps(SD->Inst) ||
14905               SD->isPartOfBundle() ==
14906                   (SDTE && !doesNotNeedToSchedule(SDTE->Scalars))) &&
