14956 unsigned BoUpSLP::getVectorElementSize(Value *V) {
14957   // If V is a store, just return the width of the stored value (or value
14958   // truncated just before storing) without traversing the expression tree.
14959   // This is the common case.
14960   if (auto *Store = dyn_cast<StoreInst>(V))
14961     return DL->getTypeSizeInBits(Store->getValueOperand()->getType());
14962 
14963   if (auto *IEI = dyn_cast<InsertElementInst>(V))
14964     return getVectorElementSize(IEI->getOperand(1));
14965 
14966   auto E = InstrElementSize.find(V);
14967   if (E != InstrElementSize.end())
14968     return E->second;
14969 
14970   // If V is not a store, we can traverse the expression tree to find loads
14971   // that feed it. The type of the loaded value may indicate a more suitable
14972   // width than V's type. We want to base the vector element size on the width
14973   // of memory operations where possible.
14974   SmallVector<std::tuple<Instruction *, BasicBlock *, unsigned>> Worklist;
14975   SmallPtrSet<Instruction *, 16> Visited;
14976   if (auto *I = dyn_cast<Instruction>(V)) {
14977     Worklist.emplace_back(I, I->getParent(), 0);
14978     Visited.insert(I);
14979   }
14980 
14981   // Traverse the expression tree in bottom-up order looking for loads. If we
14982   // encounter an instruction we don't yet handle, we give up.
14983   auto Width = 0u;
14984   Value *FirstNonBool = nullptr;
14985   while (!Worklist.empty()) {
14986     auto [I, Parent, Level] = Worklist.pop_back_val();
14987 
14988     // We should only be looking at scalar instructions here. If the current
14989     // instruction has a vector type, skip.
14990     auto *Ty = I->getType();
14991     if (isa<VectorType>(Ty))
14992       continue;
14993     if (Ty != Builder.getInt1Ty() && !FirstNonBool)
14994       FirstNonBool = I;
14995     if (Level > RecursionMaxDepth)
14996       continue;
14997 
14998     // If the current instruction is a load, update MaxWidth to reflect the
14999     // width of the loaded value.
15000     if (isa<LoadInst, ExtractElementInst, ExtractValueInst>(I))
15001       Width = std::max<unsigned>(Width, DL->getTypeSizeInBits(Ty));
15002 
15003     // Otherwise, we need to visit the operands of the instruction. We only
15004     // handle the interesting cases from buildTree here. If an operand is an
15005     // instruction we haven't yet visited and from the same basic block as the
15006     // user or the use is a PHI node, we add it to the worklist.
15007     else if (isa<PHINode, CastInst, GetElementPtrInst, CmpInst, SelectInst,
15008                  BinaryOperator, UnaryOperator>(I)) {
15009       for (Use &U : I->operands()) {
15010         if (auto *J = dyn_cast<Instruction>(U.get()))
15011           if (Visited.insert(J).second &&
15012               (isa<PHINode>(I) || J->getParent() == Parent)) {
15013             Worklist.emplace_back(J, J->getParent(), Level + 1);
15014             continue;
15015           }
15016         if (!FirstNonBool && U.get()->getType() != Builder.getInt1Ty())
15017           FirstNonBool = U.get();
15018       }
15019     } else {
15020       break;
15021     }
15022   }
15023 
15024   // If we didn't encounter a memory access in the expression tree, or if we
15025   // gave up for some reason, just return the width of V. Otherwise, return the
15026   // maximum width we found.
15027   if (!Width) {
15028     if (V->getType() == Builder.getInt1Ty() && FirstNonBool)
15029       V = FirstNonBool;
15030     Width = DL->getTypeSizeInBits(V->getType());
15031   }
15032 
15033   for (Instruction *I : Visited)
15034     InstrElementSize[I] = Width;
15035 
15036   return Width;
15037 }
