14218 void BoUpSLP::optimizeGatherSequence() {
14219   LLVM_DEBUG(dbgs() << "SLP: Optimizing " << GatherShuffleExtractSeq.size()
14220                     << " gather sequences instructions.\n");
14221   // LICM InsertElementInst sequences.
14222   for (Instruction *I : GatherShuffleExtractSeq) {
14223     if (isDeleted(I))
14224       continue;
14225 
14226     // Check if this block is inside a loop.
14227     Loop *L = LI->getLoopFor(I->getParent());
14228     if (!L)
14229       continue;
14230 
14231     // Check if it has a preheader.
14232     BasicBlock *PreHeader = L->getLoopPreheader();
14233     if (!PreHeader)
14234       continue;
14235 
14236     // If the vector or the element that we insert into it are
14237     // instructions that are defined in this basic block then we can't
14238     // hoist this instruction.
14239     if (any_of(I->operands(), [L](Value *V) {
14240           auto *OpI = dyn_cast<Instruction>(V);
14241           return OpI && L->contains(OpI);
14242         }))
14243       continue;
14244 
14245     // We can hoist this instruction. Move it to the pre-header.
14246     I->moveBefore(PreHeader->getTerminator());
14247     CSEBlocks.insert(PreHeader);
14248   }
14249 
14250   // Make a list of all reachable blocks in our CSE queue.
14251   SmallVector<const DomTreeNode *, 8> CSEWorkList;
14252   CSEWorkList.reserve(CSEBlocks.size());
