14259   // Sort blocks by domination. This ensures we visit a block after all blocks
14260   // dominating it are visited.
14261   llvm::sort(CSEWorkList, [](const DomTreeNode *A, const DomTreeNode *B) {
14262     assert((A == B) == (A->getDFSNumIn() == B->getDFSNumIn()) &&
14263            "Different nodes should have different DFS numbers");
14264     return A->getDFSNumIn() < B->getDFSNumIn();
