14311   // instructions. TODO: We can further optimize this scan if we split the
14312   // instructions into different buckets based on the insert lane.
14313   SmallVector<Instruction *, 16> Visited;
14314   for (auto I = CSEWorkList.begin(), E = CSEWorkList.end(); I != E; ++I) {
14315     assert(*I &&
14316            (I == CSEWorkList.begin() || !DT->dominates(*I, *std::prev(I))) &&
14317            "Worklist not sorted properly!");
14318     BasicBlock *BB = (*I)->getBlock();
14319     // For all instructions in blocks containing gather sequences:
14320     for (Instruction &In : llvm::make_early_inc_range(*BB)) {
14321       if (isDeleted(&In))
14322         continue;
14323       if (!isa<InsertElementInst, ExtractElementInst, ShuffleVectorInst>(&In) &&
