14331         SmallVector<int> NewMask;
14332         if (IsIdenticalOrLessDefined(&In, V, NewMask) &&
14333             DT->dominates(V->getParent(), In.getParent())) {
14334           In.replaceAllUsesWith(V);
14335           eraseInstruction(&In);
14336           if (auto *SI = dyn_cast<ShuffleVectorInst>(V))
14337             if (!NewMask.empty())
14338               SI->setShuffleMask(NewMask);
14339           Replaced = true;
14340           break;
14341         }
14342         if (isa<ShuffleVectorInst>(In) && isa<ShuffleVectorInst>(V) &&
14343             GatherShuffleExtractSeq.contains(V) &&
14344             IsIdenticalOrLessDefined(V, &In, NewMask) &&
14345             DT->dominates(In.getParent(), V->getParent())) {
14346           In.moveAfter(V);
14347           V->replaceAllUsesWith(&In);
14348           eraseInstruction(V);
14349           if (auto *SI = dyn_cast<ShuffleVectorInst>(&In))
14350             if (!NewMask.empty())
14351               SI->setShuffleMask(NewMask);
14352           V = &In;
14353           Replaced = true;
14354           break;
14355         }
14356       }
14357       if (!Replaced) {
14358         assert(!is_contained(Visited, &In));
14359         Visited.push_back(&In);
14360       }
14361     }
14362   }
14363   CSEBlocks.clear();
14364   GatherShuffleExtractSeq.clear();
